import json
from datetime import datetime

class IoTGateway:
 def __init__(self, gateway_id, transmission_interval=60):
 self.gateway_id = gateway_id
 self.sensors = {}
 self.transmission_interval = transmission_interval
 self.local_storage = []

 def register_sensor(self, sensor_id, threshold):
 self.sensors[sensor_id] = {
 'threshold': threshold,
 'readings': [],
 'alert_count': 0
 }

 def process_reading(self, sensor_id, value, timestamp):
 if sensor_id not in self.sensors:
 return None

 sensor = self.sensors[sensor_id]
 sensor['readings'].append(value)

 # Edge analytics: Check threshold
 if value > sensor['threshold']:
 sensor['alert_count'] += 1
 self._send_alert(sensor_id, value)

 return {'sensor_id': sensor_id, 'avg': sum(sensor['readings'])/len(sensor['readings'])}

 def _send_alert(self, sensor_id, value):
 alert = {
 'gateway': self.gateway_id,
 'sensor': sensor_id,
 'value': value,
 'timestamp': datetime.now().isoformat(),
 'type': 'THRESHOLD_EXCEEDED'
 }
 print(f"ALERT: {json.dumps(alert)}")

# Demo
gateway = IoTGateway('GW-001')
gateway.register_sensor('TEMP-01', threshold=28.0)
for i in range(5):
 temp = 25 + i * 0.8
 gateway.process_reading('TEMP-01', temp, datetime.now())
